// Validate and normalize incoming request
const body = $input.first().json.body;

if (!body.inputs || !Array.isArray(body.inputs) || body.inputs.length === 0) {
  throw new Error('inputs array is required. Each item: { query: string } — can be LinkedIn URL, name, or company');
}
if (!body.meeting_date) throw new Error('meeting_date is required');
if (!body.uzbek_participants || !Array.isArray(body.uzbek_participants)) throw new Error('uzbek_participants array is required');
if (!body.user_id) throw new Error('user_id (Telegram ID) is required');

const docId = `doc_${Date.now()}_${body.user_id}`;

return [{
  json: {
    inputs: body.inputs,
    meeting_date: body.meeting_date,
    meeting_time: body.meeting_time || '11:00',
    uzbek_participants: body.uzbek_participants,
    user_id: body.user_id,
    doc_id: docId
  }
}];

// Split inputs array into individual items for parallel research
const data = $input.first().json;

return data.inputs.map((item, index) => ({
  json: {
    query: item.query,
    index: index,
    total: data.inputs.length,
    meeting_date: data.meeting_date,
    meeting_time: data.meeting_time,
    uzbek_participants: data.uzbek_participants,
    user_id: data.user_id,
    doc_id: data.doc_id
  }
}));

// Validate research result and merge with metadata
const research = $input.first().json;
const meta = $('Split Inputs').first().json;

if (!research.success) {
  throw new Error(`Research failed for "${meta.query}": ${research.error}`);
}

if (!research.person || !research.person.full_name) {
  throw new Error(`Could not extract person data for "${meta.query}"`);
}

return [{
  json: {
    index: meta.index,
    total: meta.total,
    meeting_date: meta.meeting_date,
    meeting_time: meta.meeting_time,
    uzbek_participants: meta.uzbek_participants,
    user_id: meta.user_id,
    doc_id: meta.doc_id,
    query: meta.query,
    person: research.person,
    company_info: research.company_info,
    education: research.education || [],
    career: research.career || [],
    confidence: research.person.confidence || 'medium'
  }
}];

// Aggregate all researched profiles into one document
const items = $input.all();

// Group by doc_id
const grouped = {};
for (const item of items) {
  const docId = item.json.doc_id;
  if (!grouped[docId]) {
    grouped[docId] = {
      doc_id: docId,
      user_id: item.json.user_id,
      meeting_date: item.json.meeting_date,
      meeting_time: item.json.meeting_time,
      uzbek_participants: item.json.uzbek_participants,
      profiles: []
    };
  }
  grouped[docId].profiles.push({
    index: item.json.index,
    query: item.json.query,
    person: item.json.person,
    company_info: item.json.company_info,
    education: item.json.education,
    career: item.json.career,
    confidence: item.json.confidence
  });
}

// Sort by original index
for (const docId in grouped) {
  grouped[docId].profiles.sort((a, b) => a.index - b.index);
}

return Object.values(grouped).map(doc => ({ json: doc }));

// Build final document structure for DOCX service
const data = $input.first().json;
const profiles = data.profiles;

const docStructure = {
  doc_id: data.doc_id,
  meeting_date: data.meeting_date,
  meeting_time: data.meeting_time,
  uzbek_participants: data.uzbek_participants,
  sections: []
};

// Build all foreign participants list (for participants table)
const foreignParticipants = profiles.map(p => ({
  name: p.person.full_name,
  position: p.person.position,
  company: p.person.company
}));

for (let i = 0; i < profiles.length; i++) {
  const p = profiles[i];

  // 1. Company Info Page
  docStructure.sections.push({
    type: 'company_info',
    company_name: p.company_info.name,
    description: p.company_info.description,
    uzbekistan_connection: p.company_info.uzbekistan_connection,
    activity_title: p.company_info.activity_title,
    activity_description: p.company_info.activity_description
  });

  // 2. Participants Table (only once, after first company info)
  if (i === 0) {
    docStructure.sections.push({
      type: 'participants_table',
      meeting_date: data.meeting_date,
      meeting_time: data.meeting_time,
      uzbek_participants: data.uzbek_participants,
      foreign_participants: foreignParticipants
    });
  }

  // 3. Bio Page
  docStructure.sections.push({
    type: 'bio',
    full_name: p.person.full_name,
    position: p.person.position,
    company: p.person.company,
    education: p.education,
    career: p.career
  });
}

return [{ json: docStructure }];

